const regularity=(v:string)=>{const b=baseVerb(v);return (b.endsWith("er")&&b!=="aller"&&!I[b])||(b.endsWith("ir")&&!I[b])?"régulier":"irrégulier"};
const trait=(v:string)=>isPro(v)?"verbe pronominal":VERB_TRAITS[v]||"transitif / intransitif selon l’usage";

function LearningTips(){
 const [index,setIndex]=useState(0);
 const [pausedUntil,setPausedUntil]=useState(0);
 const timer=useRef<ReturnType<typeof setInterval>|null>(null);
 const move=(direction:number)=>{setIndex(i=>(i+direction+TIPS.length)%TIPS.length);setPausedUntil(Date.now()+20000)};
 useEffect(()=>{
  timer.current=setInterval(()=>{if(Date.now()>=pausedUntil)setIndex(i=>(i+1)%TIPS.length)},9000);
  return()=>{if(timer.current)clearInterval(timer.current)};
 },[pausedUntil]);
 return <section className="conj-learning-card" aria-label="معلومات مبسطة عن تصريف الأفعال">
  <button onClick={()=>move(-1)} aria-label="المعلومة السابقة"><ChevronRight/></button>
  <div className="conj-learning-body"><span><Sparkles/> معلومة سريعة</span><p key={index}>{TIPS[index]}</p><div>{TIPS.map((_,i)=><i key={i} className={i===index?'active':''}/>)}</div></div>
  <button onClick={()=>move(1)} aria-label="المعلومة التالية"><ChevronLeft/></button>
 </section>
}

