const subjImperfect=(v:string)=>{const b=baseVerb(v),r=b.endsWith("ir")?b.slice(0,-2):stem(b);return [r+"isse",r+"isses",r+"ît",r+"issions",r+"issiez",r+"issent"]};
const subjRows=(forms:string[])=>forms.map((x,i)=>["que je","que tu","qu’il / elle","que nous","que vous","qu’ils / elles"][i]+" "+x);
const auxImp=(a:"avoir"|"être")=>a==="avoir"?["aie","ayons","ayez"]:["sois","soyons","soyez"];
const auxPart=(a:"avoir"|"être")=>a==="avoir"?"ayant":"étant";

const vowel=/^[aeiouyhàâäéèêëîïôöùûü]/i;
const proPrefix=(i:number,form:string)=>{const short=vowel.test(form);return [[short?"j’":"je ",short?"m’":"me "],["tu ",short?"t’":"te "],["il / elle ",short?"s’":"se "],["nous ","nous "],["vous ","vous "],["ils / elles ",short?"s’":"se "]][i]};
const rows=(x:string[],v?:string)=>x.map((f,i)=>{if(!v||!isPro(v))return i===0&&vowel.test(f)?"j’"+f:P[i]+" "+f;const [sub,ref]=proPrefix(i,f);return sub+ref+f});
