"admirer":[{fr:"admirer le paysage",ar:"الإعجاب بالمنظر",example:"Les voyageurs admirent le paysage depuis le train.",translation:"يعجب المسافرون بالمنظر من القطار."},{fr:"admirer le travail de quelqu’un",ar:"الإعجاب بعمل شخص",example:"J’admire le travail accompli par cette équipe.",translation:"أعجب بالعمل الذي أنجزه هذا الفريق."}],
"adopter":[{fr:"adopter une stratégie",ar:"تبني استراتيجية",example:"L’entreprise adopte une stratégie plus durable.",translation:"تتبنى الشركة استراتيجية أكثر استدامة."},{fr:"adopter une mesure",ar:"اعتماد إجراء",example:"Le gouvernement adopte une nouvelle mesure.",translation:"تعتمد الحكومة إجراءً جديدًا."}],
"affronter":[{fr:"affronter une difficulté",ar:"مواجهة صعوبة",example:"Nous affrontons cette difficulté avec patience.",translation:"نواجه هذه الصعوبة بصبر."},{fr:"affronter un adversaire",ar:"مواجهة خصم",example:"Notre équipe affronte un adversaire expérimenté.",translation:"يواجه فريقنا خصمًا متمرسًا."}],
"analyser":[{fr:"analyser les résultats",ar:"تحليل النتائج",example:"Les chercheurs analysent les résultats de l’étude.",translation:"يحلل الباحثون نتائج الدراسة."},{fr:"analyser une situation",ar:"تحليل وضع",example:"Le comité analyse la situation avant de décider.",translation:"تحلل اللجنة الوضع قبل اتخاذ القرار."}],
"appliquer":[{fr:"appliquer une règle",ar:"تطبيق قاعدة",example:"Le personnel applique les règles de sécurité.",translation:"يطبق الموظفون قواعد السلامة."},{fr:"appliquer une règle à un cas",ar:"تطبيق قاعدة على حالة",example:"Le juge applique la règle à ce cas particulier.",translation:"يطبق القاضي القاعدة على هذه الحالة الخاصة."}],
"apprécier":[{fr:"apprécier un service",ar:"تقدير خدمة",example:"Les clients apprécient la rapidité du service.",translation:"يقدّر العملاء سرعة الخدمة."},{fr:"apprécier de faire quelque chose",ar:"الاستمتاع بالقيام بشيء",example:"J’apprécie de travailler dans une équipe calme.",translation:"أستمتع بالعمل ضمن فريق هادئ."}],
"approuver":[{fr:"approuver un budget",ar:"الموافقة على ميزانية",example:"Le conseil approuve le budget annuel.",translation:"يوافق المجلس على الميزانية السنوية."},{fr:"approuver une décision",ar:"الموافقة على قرار",example:"La majorité approuve la décision finale.",translation:"توافق الأغلبية على القرار النهائي."}],
"arranger":[{fr:"arranger un rendez-vous",ar:"ترتيب موعد",example:"Je vais arranger un rendez-vous avec le médecin.",translation:"سأرتب موعدًا مع الطبيب."},{fr:"arranger une situation",ar:"تسوية وضع",example:"Une discussion franche peut arranger la situation.",translation:"قد يسوي نقاش صريح الوضع."}],
"autoriser":[{fr:"autoriser l’accès",ar:"السماح بالدخول",example:"Le responsable autorise l’accès à la salle.",translation:"يسمح المسؤول بالدخول إلى القاعة."},{fr:"autoriser quelqu’un à faire quelque chose",ar:"السماح لشخص بالقيام بشيء",example:"Le médecin l’autorise à reprendre le sport.",translation:"يسمح له الطبيب باستئناف الرياضة."}],

"questionner":[{fr:"questionner un témoin",ar:"استجواب شاهد",example:"La police questionne le témoin après l’incident.",translation:"تستجوب الشرطة الشاهد بعد الحادث."},{fr:"questionner quelqu’un sur un sujet",ar:"سؤال شخص عن موضوع",example:"Le journaliste questionne la ministre sur le nouveau projet.",translation:"يسأل الصحفي الوزيرة عن المشروع الجديد."}],
"quérir":[{fr:"quérir de l’aide",ar:"طلب المساعدة",example:"Le chevalier partit quérir de l’aide au village voisin.",translation:"ذهب الفارس لطلب المساعدة من القرية المجاورة."},{fr:"venir quérir quelqu’un",ar:"المجيء لأخذ شخص",example:"Un messager vient quérir le médecin au château.",translation:"يأتي رسول لأخذ الطبيب إلى القصر."}],
"quereller":[{fr:"quereller un voisin",ar:"مخاصمة جار",example:"Il querelle son voisin pour une place de stationnement.",translation:"يخاصم جاره بسبب موقف سيارة."},{fr:"quereller un enfant",ar:"توبيخ طفل",example:"La mère querelle doucement l’enfant après sa bêtise.",translation:"توبّخ الأم الطفل بلطف بعد تصرفه الخاطئ."}],
"se quereller":[{fr:"se quereller avec quelqu’un",ar:"التشاجر مع شخص",example:"Les deux collègues se querellent à propos du planning.",translation:"يتشاجر الزميلان بشأن جدول العمل."},{fr:"se quereller pour rien",ar:"التشاجر بلا سبب",example:"Ils se sont querellés pour une remarque sans importance.",translation:"تشاجروا بسبب ملاحظة غير مهمة."}],
"quêter":[{fr:"quêter des dons",ar:"جمع التبرعات",example:"L’association quête des dons pour l’hôpital.",translation:"تجمع الجمعية التبرعات للمستشفى."},{fr:"quêter l’approbation",ar:"التماس الموافقة",example:"Il quête l’approbation de son responsable avant d’agir.",translation:"يلتمس موافقة مسؤوله قبل التصرف."}],
