"quantifier":[{fr:"quantifier les pertes",ar:"تحديد الخسائر كميًا",example:"Les experts quantifient les pertes après l’incendie.",translation:"يحدّد الخبراء الخسائر كميًا بعد الحريق."},{fr:"quantifier un risque",ar:"قياس خطر",example:"Le rapport quantifie le risque financier du projet.",translation:"يحدّد التقرير مقدار الخطر المالي للمشروع."}],
