"quadrupler":[{fr:"quadrupler la production",ar:"مضاعفة الإنتاج أربع مرات",example:"L’usine quadruple sa production pendant la saison.",translation:"تضاعف المصنع إنتاجه أربع مرات خلال الموسم."},{fr:"quadrupler en valeur",ar:"الارتفاع إلى أربعة أمثال",example:"Le prix a quadruplé en dix ans.",translation:"ارتفع السعر إلى أربعة أمثاله خلال عشر سنوات."}],
