"quarter":[{fr:"quarter un échantillon",ar:"تقسيم عينة إلى أرباع",example:"Le technicien quarte l’échantillon avant l’analyse.",translation:"يقسّم الفني العينة إلى أرباع قبل التحليل."},{fr:"quarter un minerai",ar:"تقسيم خام بطريقة الربع",example:"Le laboratoire quarte le minerai pour obtenir un prélèvement représentatif.",translation:"يقسّم المختبر الخام بطريقة الربع للحصول على عينة ممثلة."}],
"quintupler":[{fr:"quintupler les ventes",ar:"مضاعفة المبيعات خمس مرات",example:"La campagne a quintuplé les ventes en trois mois.",translation:"ضاعفت الحملة المبيعات خمس مرات خلال ثلاثة أشهر."},{fr:"quintupler de volume",ar:"الزيادة إلى خمسة أمثال",example:"La demande pourrait quintupler d’ici l’été.",translation:"قد يزداد الطلب إلى خمسة أمثاله بحلول الصيف."}],
"quitter":[{fr:"quitter le bureau",ar:"مغادرة المكتب",example:"Elle quitte le bureau à dix-sept heures.",translation:"تغادر المكتب عند الساعة الخامسة مساءً."},{fr:"quitter quelqu’un",ar:"ترك شخص",example:"Il a quitté son associé après un long désaccord.",translation:"ترك شريكه بعد خلاف طويل."}],
