"qualifier":[{fr:"qualifier un comportement",ar:"وصف سلوك",example:"Le juge qualifie ce comportement de dangereux.",translation:"يصف القاضي هذا السلوك بأنه خطير."},{fr:"qualifier une équipe",ar:"تأهيل فريق",example:"Cette victoire qualifie l’équipe pour la finale.",translation:"يؤهل هذا الفوز الفريق للنهائي."}],
