function stage1Future(p:string):string{return p.split(" أو ").map(x=>"س"+x).join(" أو ")}
function stage1Arabic(title:string,index:number,verb:string,ctx:string):string{
 const p=STAGE1_AR_PRESENT[verb][Math.min(index,5)],past=STAGE1_AR_PAST[verb][Math.min(index,5)],pron=STAGE1_AR_PRONOUN[Math.min(index,5)],kana=STAGE1_AR_KANA[Math.min(index,5)],future=stage1Future(p);
 if(title==="Présent")return `${pron} ${p} ${ctx} في الوقت الحاضر.`;
 if(title==="Passé composé")return `${past} ${ctx} أمس بعد اكتمال الترتيبات.`;
 if(title==="Imparfait")return `${kana} ${p} ${ctx} بانتظام عندما كانت الظروف مختلفة.`;
 if(title==="Plus-que-parfait")return `${kana} قد ${past} ${ctx} قبل وصول المسؤول.`;
 if(title==="Passé simple")return `${past} ${ctx} في ذلك اليوم ضمن سياق السرد.`;
 if(title==="Passé antérieur")return `ما إن ${past} ${ctx} حتى بدأت المرحلة التالية.`;
 if(title==="Futur simple")return `${pron} ${future} ${ctx} غدًا وفق الخطة الجديدة.`;
 if(title==="Futur antérieur")return `${pron} سيكون قد ${past} ${ctx} قبل اجتماع الغد.`;
 if(title==="Conditionnel présent")return `${kana} ${future} ${ctx} لو سمحت الظروف بذلك.`;
 if(title==="Conditionnel passé")return `لو وصلت المعلومات في الوقت المناسب، لكان الفعل المتعلق بـ${ctx} قد اكتمل.`;
 if(title==="Subjonctif présent")return `من الضروري أن ${p} ${ctx} قبل اتخاذ القرار.`;
 if(title==="Subjonctif passé composé")return `يسرّ المسؤول أن ${past} ${ctx} قبل انتهاء المهلة.`;
 if(title==="Subjonctif imparfait")return `كان المدير يريد أن ${p} ${ctx} في ذلك الوقت.`;
 if(title==="Subjonctif plus-que-parfait")return `كان المدير يشك في أن ${past} ${ctx} قبل نشر التقرير.`;
 if(title==="Impératif présent")return `قم الآن بالفعل المطلوب في سياق ${ctx}.`;
 if(title==="Impératif passé")return `ليكن الفعل المطلوب في سياق ${ctx} قد اكتمل قبل الموعد المحدد.`;
 if(title==="Infinitif présent")return `إن القيام بالفعل في سياق ${ctx} يتطلب انتباهًا ودقة.`;
 if(title==="Infinitif passé")return `بعد إتمام الفعل في سياق ${ctx}، اعتمد المسؤول الخطوة التالية.`;
 if(title==="Participe présent")return `أثناء القيام بالفعل في سياق ${ctx}، واصل الشخص مهمته دون انقطاع.`;
 if(title==="Participe passé"&&index===0)return `النتيجة المرتبطة بالفعل في سياق ${ctx} موثقة في الملف النهائي.`;
 if(title==="Participe passé")return `بعد إتمام الفعل في سياق ${ctx}، تابع الفريق عمله.`;
 if(title==="Gérondif présent")return `من خلال القيام بالفعل في سياق ${ctx}، يصبح سير العمل أكثر وضوحًا.`;
 return `بعد إتمام الفعل في سياق ${ctx}، أُرسل التقرير النهائي.`;
}
