function stage1Example(form:string,title:string,index:number,verb:string):[string,string]|undefined{
 if(!STAGE1_VERBS.has(verb))return undefined;
 const ctx=STAGE1_CONTEXTS[verb][Math.min(index,5)];
 const t=(STAGE1_TIME[title]||[])[Math.min(index,5)];
 let fr="";
 if(title==="Présent"||title==="Passé composé"||title==="Imparfait"||title==="Plus-que-parfait"||title==="Passé simple"||title==="Futur simple"||title==="Conditionnel présent")fr=`${cap(form)} ${ctx.fr} ${t}.`;
 else if(title==="Passé antérieur")fr=`Dès que ${form} ${ctx.fr}, la phase suivante commença.`;
 else if(title==="Futur antérieur")fr=`${cap(form)} ${ctx.fr} avant la réunion prévue demain.`;
 else if(title==="Conditionnel passé")fr=`${cap(form)} ${ctx.fr} si l’information était arrivée à temps.`;
 else if(title==="Subjonctif présent")fr=`Le responsable souhaite ${form} ${ctx.fr} avant la validation finale.`;
 else if(title==="Subjonctif passé composé")fr=`Le responsable est satisfait ${form} ${ctx.fr} avant l’expiration du délai.`;
 else if(title==="Subjonctif imparfait")fr=`Le directeur voulait ${form} ${ctx.fr} à cette étape du récit.`;
 else if(title==="Subjonctif plus-que-parfait")fr=`Le directeur doutait ${form} ${ctx.fr} avant la publication du rapport.`;
 else if(title==="Impératif présent")fr=`${cap(form)} ${ctx.fr} dès maintenant.`;
 else if(title==="Impératif passé")fr=`${cap(form)} ${ctx.fr} avant l’heure convenue.`;
 else if(title==="Infinitif présent")fr=`${cap(form)} ${ctx.fr} demande une préparation attentive.`;
 else if(title==="Infinitif passé")fr=`Après ${form} ${ctx.fr}, le responsable a validé l’étape suivante.`;
 else if(title==="Participe présent")fr=`${cap(form)} ${ctx.fr}, la personne concernée a poursuivi sa mission.`;
 else if(title==="Participe passé"&&index===0)return [STAGE1_PP_SENTENCE[verb],STAGE1_PP_AR[verb]];
 else if(title==="Participe passé")fr=`${cap(form)} ${ctx.fr}, l’équipe a poursuivi son travail sans retard.`;
 else if(title==="Gérondif présent")fr=`${cap(form)} ${ctx.fr}, vous facilitez le déroulement du travail.`;
 else if(title==="Gérondif passé")fr=`${cap(form)} ${ctx.fr}, ils ont transmis le compte rendu final.`;
 else return undefined;
 return [fr,stage1Arabic(title,index,verb,ctx.ar)];
}


